LNotchUtil.menuButtonH  = 0
LNotchUtil.menuButtonY  = 0
LNotchUtil.offsetY  = 0

function LNotchUtil.InitNotch()
	if LWxHelper.IsMiniGamePlatform() then
		LNotchUtil.DoWxInit()
	else
		LNotchUtil.DoNormalInit()
	end
	--LNotchUtil.DebugNotch(0, 46,585, 1266 - 75.5 - 46)

	LNotchUtil.UpdateNotchArea()

	LNotchUtil.IsInit = true

	GF.OpenWndTouch('UINotch')
	LNativeHelper.NotchFit("0")
end

function LNotchUtil.DoNormalInit()
	LNotchUtil.IsUseHigher = LNotchUtil.IsHigherVersion()
	LNotchUtil.IsUseHigher = nil

	local safeArea = UScreen.safeArea

	if CS.IsOSIos() then
		local bottomY = safeArea.y
		if bottomY ~= 0 then
			local newY = math.floor(bottomY * 0.6)
			safeArea.y = newY
			safeArea.height = safeArea.height + bottomY - newY
		end

		--灵动岛顶部直接全屏
		--if LPlatformUtil.IsLingDongDao() then
		--	safeArea.height = UScreen.height - safeArea.y
		--end

		if LPlatformUtil.IsIphoneNotch() or (UScreen.height - safeArea.height) > 0 then
			LNotchUtil.notchEnable = true
		end
	end
	if LOG_INFO_ENABLED then
		printInfo("NotchUtil", "当前运行平台："..tostring(CS.UApplication.platform))
	end
	if CS.IsOSOpenHarmony() then
		if LOG_INFO_ENABLED then
			printInfo("NotchUtil", "鸿蒙设备")
		end
		if (UScreen.height - safeArea.height) > 0 then
			LNotchUtil.notchEnable = true
		end
	end

	LNotchUtil.OriginalNotchWidth = UScreen.width - safeArea.width
	LNotchUtil.OriginalNotchHeight = UScreen.height - safeArea.height
	LNotchUtil.SafeArea = safeArea

	LNotchUtil.NotchWidth = LNotchUtil.OriginalNotchWidth
	LNotchUtil.NotchHeight = LNotchUtil.OriginalNotchHeight

	LNotchUtil.width = UScreen.width
	LNotchUtil.height = UScreen.height
end

function LNotchUtil.DoWxInit()
	--微信的屏幕坐标系是左上角为原点， y轴朝下， x轴朝右
	--需要转成unity的坐标系，进行计算
	local safeArea
	--safeArea = UScreen.safeArea
	--gprint("DoWxInit safeArea", safeArea.x, safeArea.y, safeArea.width, safeArea.height)
	--0,0, 1080, 2400

	local x, y , w, h = LWxHelper.WxGetSafeArea()
	local screenW , screenH = LWxHelper.WxGetScreenSize()
	if screenH < screenW then --交换 确保竖屏
		local tmp = screenH
		screenH = screenW
		screenW = tmp
	end

	--gprint("DoWxInit", x, y, w, h, screenW, screenH, LWxHelper.IsInAndroid(), LWxHelper.IsInIos())
	--0,800, 360, 761, 360, 800

	--if LWxHelper.IsInAndroid() or LWxHelper.IsInIos() then
	--	local mbx, mby , mbw, mbh = LWxHelper.WxGetMenuButtonBoundArea()
	--	--mby = screenH - mby
	--	--safeArea = UnityEngine.Rect.New(x, y, w, mby - y)
	--	safeArea = UnityEngine.Rect.New(x, screenH - y, w, screenH - mby)
	--	--0,84, 360, 800-84
	--	--gprint("DoWxInit WxGetMenuButtonBoundArea", mbx, mby, mbw, mbh)
	--	--248,84, 96, 32
	--	--gprint("DoWxInit safeArea last", x, screenH - y, w, screenH - mby)
	--	--0,0, 360, 800-84
	--else
	--	safeArea = UnityEngine.Rect.New(0, 0, w, h)
	--end

	local pf = LWxHelper.GetWxPlatform()
	if pf == "android" or pf == "ios" or pf == "devtools" then
		y = screenH - y
		local mbx, mby, mbw, mbh = LWxHelper.WxGetMenuButtonBoundArea()
		safeArea = UnityEngine.Rect.New(x, y, w, screenH - mby - y)
		--gprint("DoWxInit WxGetMenuButtonBoundArea", mbx, mby, mbw, mbh, y)
		LNotchUtil.menuButtonY = mby
		LNotchUtil.menuButtonH = mbh
	else
		safeArea = UnityEngine.Rect.New(0, 0, w, h)
	end

	LNotchUtil.OriginalNotchWidth = screenW - safeArea.width
	LNotchUtil.OriginalNotchHeight = screenH - safeArea.height
	LNotchUtil.SafeArea = safeArea

	LNotchUtil.NotchWidth = LNotchUtil.OriginalNotchWidth
	LNotchUtil.NotchHeight = LNotchUtil.OriginalNotchHeight

	LNotchUtil.width = screenW
	LNotchUtil.height = screenH

	if (screenH - safeArea.height) > 0  then
		LNotchUtil.notchEnable = true
	end
end

function LNotchUtil.OnWXResize()
	LNotchUtil.DoWxInit()
	LNotchUtil.UpdateNotchArea()
	CS.NotchFit("0")
end


