function LNotchUtil.UpdateNotchArea()
	local safeArea = LNotchUtil.SafeArea

	local uWidth = LNotchUtil.width
	local uHeight = LNotchUtil.height

	safeArea.x = 0
	safeArea.width = uWidth

	if CS.IsOSIos() then

	else
		--safeArea.y = LNotchUtil.changeBottomY or 0
		safeArea.height = uHeight - LNotchUtil.NotchHeight

		local sh = safeArea.height
		local sw = safeArea.width
		local sRate = sh / sw
		local dRate = 1400 / 640
		if sRate > dRate then
			safeArea.height = sw * 1400 / 640
			LNotchUtil.NotchHeight = uHeight - safeArea.height
			LNotchUtil.notchEnable = true
		end
	end


	LNotchUtil.SafeArea = safeArea

	local pos = safeArea.position
	local size = Vector2(safeArea.width,safeArea.height + pos.y)

	local designWidth = LGameQuality.SCREEN_WIDTH_DESIGN-- 设计分辨率
	local designHeight = LGameQuality.SCREEN_HEIGHT_DESIGN-- 设计分辨率

	local designRate = designWidth / designHeight
	local nowRate = uWidth / uHeight
	if designRate < nowRate then
		local newWidth = uHeight * designWidth / designHeight
		local anchorRate = (uWidth - newWidth) / uWidth * 0.5
		anchorRate = math.modf(anchorRate * 10000) / 10000
		pos.x = anchorRate
		size.x = 1 - anchorRate
	else
		pos.x = 0
		size.x = 1
	end

	if not LNotchUtil.notchEnable then
		pos.y = 0
		size.y = 1
	else
		pos.y = pos.y / uHeight
		size.y = size.y / uHeight
	end
	
	LNotchUtil.NotchAnchorMin = pos
	LNotchUtil.NotchAnchorMax = size

	FireEvent(EventNames.NOTCH_SAFE_AREA_UPDATE)
	LNotchUtil.LogNotchInfo()
	LGamePostProcess:InitPostProcess()
	LGamePostProcess:InitNotchAnchor(size, pos)
end

