function LNotchUtil.IsHigherVersion()
	if not CS.IsOSAndroid() then return false end

	--Unity 2019 并且操作系统是androidp，即是api28 的

	local appLevel = LNativeHelper.GetCurrentApiVersion()
	if not appLevel then
		local osStr = CS.SystemInfo.operatingSystem
		local appInst = string.match(osStr,"API%-(%d+)")
		appLevel =appInst and tonumber(appInst)
	end
	if not appLevel or appLevel < 28 then
		return false
	end

	local unityVer = CS.UApplication.unityVersion
	local verList1 = string.split(unityVer, ".") or {}
	local verInt = tonumber(verList1[1]) or 0
	if verInt >= 2019 then
		return true
	end

	return false
end

function LNotchUtil.ChangeNotchArea(notchEnable, notchWidth, notchHeight)
	local safeArea = UScreen.safeArea
	local currentResolution = UScreen.currentResolution
	LogWarn(string.format("[LNotchUtil unity] Screen = %sx%s | safe area = %sx%s pos = %sx%s | currentResolution =%sx%s", UScreen.width, UScreen.height, safeArea.width, safeArea.height, safeArea.x,safeArea.y,currentResolution.width,currentResolution.height))

	--//use notch cfg
	local useNotchCfg = false
	local cfgHeight = LNotchUtil.GetNotchHeight()
	if cfgHeight then
		notchHeight = cfgHeight
		if notchHeight>0 then
			notchEnable = true
			useNotchCfg = true
		end
	end

	LNotchUtil.NotchWidth = notchWidth
	LNotchUtil.NotchHeight = notchHeight

	local oldNotchEnable = LNotchUtil.notchEnable
	oldNotchEnable = oldNotchEnable and oldNotchEnable or false

	LNotchUtil.notchEnable = notchEnable

	if CS.IsOSAndroid() then
		local rectW = 0
		local rectH = 0
		if LNotchUtil.IsUseHigher then --直接使用unity自带的属性来判断
			rectW = UScreen.width
			rectH = UScreen.height
			if not notchEnable then
				notchWidth = rectW - safeArea.width
				if not useNotchCfg then
					notchHeight = rectH - safeArea.height
					if safeArea.height < rectH then
						notchEnable = true
					end
				end
			end
			LNotchUtil.notchEnable = notchEnable
			LNotchUtil.SafeArea = safeArea
			LNotchUtil.NotchWidth = notchWidth
			LNotchUtil.NotchHeight = notchHeight

			print(string.format("unity screen rect=%s|%s , safe area rect %s|%s, notchEnable %s (%s|%s)", UScreen.width, UScreen.height,safeArea.width, safeArea.height, tostring(notchEnable),tostring(notchWidth),tostring(notchHeight)))
		else
			local realRect = LNativeHelper.GetDeviceDisplayRect()
			if not string.isempty(realRect) then
				local arrResult = string.split(realRect,"|") or {}
				rectW = tonumber(arrResult[1]) or 0
				rectH = tonumber(arrResult[2]) or 0
			end
			print(string.format("unity screen rect=%s|%s , device now rect %s|%s", UScreen.width, UScreen.height, rectW,rectH))
		end
		if rectW > 0 and rectH > 0 then
			LGameQuality.SCREEN_WIDTH_DEVICE = rectW
			LGameQuality.SCREEN_HEIGHT_DEVICE = rectH
			LGameQuality.SCREEN_WIDTH_SCALE = 0
			LGameQuality.SCREEN_HEIGHT_SCALE = 0
			LNotchUtil.width = rectW
			LNotchUtil.height = rectH
			if gLGameQuality then
				gLGameQuality:ResetScreenScale()
				gLGameQuality:DoScaleScreenResolution()
			end
		end
	end

	LNotchUtil.UpdateNotchArea()

	--if oldNotchEnable ~= notchEnable then
		if gLGameUI then
			gLGameUI:DoAdjustNotchWndAnchor()
		end
	--end
end

function LNotchUtil.LogNotchInfo()
	LogWarn(string.format("[LNotchUtil] Screen = %sx%s | safe area = %sx%s ", UScreen.width, UScreen.height, LNotchUtil.SafeArea.width, LNotchUtil.SafeArea.height))
	LogWarn(string.format("[LNotchUtil] notch area = %sx%s | anchorMin = %s | anchorMax = %s", LNotchUtil.NotchWidth, LNotchUtil.NotchHeight, tostring(LNotchUtil.NotchAnchorMin), tostring(LNotchUtil.NotchAnchorMax)))
end

