function LNotchUtil.DebugNotch(rectX, rectY, rectWidth, rectHeight)
	local rectSafeArea = UnityEngine.Rect.New(rectX, rectY, rectWidth, rectHeight)
	LNotchUtil.notchEnable = true
	LNotchUtil.SafeArea = rectSafeArea
	LNotchUtil.OriginalNotchWidth = UScreen.width - rectSafeArea.width
	LNotchUtil.OriginalNotchHeight = UScreen.height - rectSafeArea.height
	LNotchUtil.NotchWidth = LNotchUtil.OriginalNotchWidth
	LNotchUtil.NotchHeight = LNotchUtil.OriginalNotchHeight
	--if y then
	--	LNotchUtil.changeBottomY = y
	--	LNotchUtil.NotchHeight = LNotchUtil.OriginalNotchHeight + y
	--end

	LNotchUtil.UpdateNotchArea()
end

