function LNotchUtil.AdjustNotchWndAnchor(wndRectTransform, adJustType)
	if not wndRectTransform then
		return
	end
	if not LNotchUtil.IsInit then return end
	adJustType = adJustType or 0

	if adJustType == 0 then
		wndRectTransform.anchorMin = Vector2(LNotchUtil.NotchAnchorMin.x, LNotchUtil.NotchAnchorMin.y)
		wndRectTransform.anchorMax = Vector2(LNotchUtil.NotchAnchorMax.x, LNotchUtil.NotchAnchorMax.y)
	elseif adJustType == 1 then
		--只处理 横向适配
		wndRectTransform.anchorMin = Vector2(LNotchUtil.NotchAnchorMin.x, 0)
		wndRectTransform.anchorMax = Vector2(LNotchUtil.NotchAnchorMax.x, 1)
	end
end

function LNotchUtil.GetNotchHeight()
	local sDeviceInfo = LNativeHelper.GetDeviceInfo()
	local arrList = string.split(sDeviceInfo,"|,") or {}
	local model = LNotchUtil.model or arrList[1] or ""
	model = string.lower(model)
	local manufacturer = LNotchUtil.manufacturer or arrList[3] or ""
	manufacturer = string.lower(manufacturer)

	local ref = GameTable.PhoneResponsiveRef
	local cfg = nil
	for k,v in pairs(ref) do
		if model == string.lower(v.model) and manufacturer == string.lower(manufacturer) then
			cfg = v
			break
		end
	end

	if cfg then
		return cfg.high
	end
end

function LNotchUtil.GetViewHorizontalLimit()
	if not LNotchUtil.IsInit then return 0,1 end
	return LNotchUtil.NotchAnchorMin.x, LNotchUtil.NotchAnchorMax.x
end


return LNotchUtil